using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    [TestClass]
    public sealed class CreateOrderTests
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
        {
            // Arrange
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
                new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 }
            };

            // Act
            var order = _sut.CreateOrder("customer-1", items);

            // Assert
            Assert.AreEqual(45.50m, order.Total);
        }

        [TestMethod]
        public void CreateOrder_WithValidItems_AssignsNonEmptyId()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };

            var order = _sut.CreateOrder("customer-1", items);

            Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        }

        [TestMethod]
        public void CreateOrder_WithValidItems_AssignsCustomerId()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };

            var order = _sut.CreateOrder("customer-42", items);

            Assert.AreEqual("customer-42", order.CustomerId);
        }

        [TestMethod]
        public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            var before = DateTime.UtcNow;

            var order = _sut.CreateOrder("customer-1", items);

            var after = DateTime.UtcNow;
            Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
        }

        [TestMethod]
        public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };

            Assert.ThrowsExactly<ArgumentNullException>(
                () => _sut.CreateOrder(null!, items));
        }

        [TestMethod]
        public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
        {
            Assert.ThrowsExactly<ArgumentNullException>(
                () => _sut.CreateOrder("customer-1", null!));
        }

        [TestMethod]
        public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
        {
            Assert.ThrowsExactly<InvalidOperationException>(
                () => _sut.CreateOrder("customer-1", []));
        }

        [TestMethod]
        public void CreateOrder_WithMultipleQuantity_CalculatesTotalCorrectly()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 7.50m, Quantity = 4 }
            };

            var order = _sut.CreateOrder("customer-1", items);

            Assert.AreEqual(30.00m, order.Total);
        }
    }

    [TestClass]
    public sealed class GetOrderTests
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void GetOrder_WithExistingId_ReturnsOrder()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            var created = _sut.CreateOrder("customer-1", items);

            var result = _sut.GetOrder(created.Id);

            Assert.IsNotNull(result);
            Assert.AreEqual(created.Id, result.Id);
        }

        [TestMethod]
        public void GetOrder_WithNonExistingId_ReturnsNull()
        {
            var result = _sut.GetOrder("nonexistent-id");

            Assert.IsNull(result);
        }
    }

    [TestClass]
    public sealed class GetOrdersByCustomerTests
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void GetOrdersByCustomer_WithOrders_ReturnsMatchingOrders()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            _sut.CreateOrder("customer-1", items);
            _sut.CreateOrder("customer-1", items);
            _sut.CreateOrder("customer-2", items);

            var results = _sut.GetOrdersByCustomer("customer-1");

            Assert.AreEqual(2, results.Count);
        }

        [TestMethod]
        public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
        {
            var results = _sut.GetOrdersByCustomer("customer-99");

            Assert.AreEqual(0, results.Count);
        }

        [TestMethod]
        public void GetOrdersByCustomer_ReturnsOnlyOrdersForSpecifiedCustomer()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            _sut.CreateOrder("customer-A", items);
            _sut.CreateOrder("customer-B", items);

            var results = _sut.GetOrdersByCustomer("customer-A");

            Assert.IsTrue(results.All(o => o.CustomerId == "customer-A"));
        }
    }
}

